```typescript
import { Observable } from "rxjs";
import { debounceTime, distinctUntilChanged, filter, switchMap } from "rxjs/operators";

interface City {
  id: string;
  name: string;
  country: string;
}

declare function searchCities$(q: string): Observable<City[]>;

export function cityAutocomplete(
  query$: Observable<string>
): Observable<City[]> {
  // switchMap cancels the prior inner subscription when a new query arrives
  // — mergeMap here would race and allow stale results to win.
  return query$.pipe(
    debounceTime(250),
    distinctUntilChanged(),
    filter((q: string): boolean => q.trim().length >= 2),
    switchMap((q: string) => searchCities$(q))
  );
}
```

Use `concatMap`. Unlike `mergeMap` (which interleaves) and `switchMap` (which cancels), `concatMap` queues each inner observable and runs them sequentially.

```typescript
import { Observable } from "rxjs";
import { concatMap } from "rxjs/operators";

interface WriteJob {
  id: string;
  payload: string;
}

interface WriteAck {
  id: string;
  persistedAt: number;
}

declare function persist$(job: WriteJob): Observable<WriteAck>;

export function orderedWrites(
  jobs$: Observable<WriteJob>
): Observable<WriteAck> {
  // concatMap: strict order, 1-at-a-time. Each persist$ completes before
  // the next job starts — ideal for ordered side effects (DB writes, logs).
  return jobs$.pipe(
    concatMap((job: WriteJob) => persist$(job))
  );
}
```

`exhaustMap` ignores new outer emissions while an inner observable is still running. That is exactly what you want on a submit button: while the POST is in flight, further clicks are dropped rather than queued (`concatMap`) or racing (`mergeMap`).

```typescript
import { Observable } from "rxjs";
import { exhaustMap } from "rxjs/operators";

interface FormValues {
  email: string;
  password: string;
}

interface SubmitResult {
  ok: boolean;
  userId?: string;
}

declare function submitForm$(v: FormValues): Observable<SubmitResult>;

export function submitWithGuard(
  click$: Observable<FormValues>
): Observable<SubmitResult> {
  return click$.pipe(
    exhaustMap((values: FormValues) => submitForm$(values))
  );
}
```

```typescript
import { Observable } from "rxjs";
import { mergeMap } from "rxjs/operators";

interface UploadTask {
  fileName: string;
  bytes: Uint8Array;
}

interface UploadResult {
  fileName: string;
  url: string;
}

declare function uploadOne$(t: UploadTask): Observable<UploadResult>;

export function boundedUploads(
  tasks$: Observable<UploadTask>
): Observable<UploadResult> {
  // mergeMap(project, concurrency) bounds in-flight inner subscriptions to 4.
  // concatMap = 1-at-a-time (too slow); switchMap = cancels prior (loses data).
  return tasks$.pipe(
    mergeMap((t: UploadTask) => uploadOne$(t), 4)
  );
