}

declare const click$: Observable<Click>;
declare const token$: Observable<AuthToken>;

// withLatestFrom: primary stream emits; secondary contributes its latest value.
// Token updates on their own do NOT produce output here.
export const stamped$: Observable<StampedClick> = click$.pipe(
  withLatestFrom(token$),
  map(([click, token]: [Click, AuthToken]): StampedClick => ({
