```typescript
import { BehaviorSubject, Observable } from "rxjs";

interface CounterState {
  value: number;
  updatedAt: number;
}

const initial: CounterState = { value: 0, updatedAt: 0 };
const state$ = new BehaviorSubject<CounterState>(initial);

// asObservable hides .next from consumers.
// Late subscribers receive the CURRENT value on subscription.
export const counter$: Observable<CounterState> = state$.asObservable();

export function increment(): void {
  const prev = state$.getValue(); // sync read — acceptable for one-shot updates
  state$.next({ value: prev.value + 1, updatedAt: Date.now() });
}

export function decrement(): void {
  const prev = state$.getValue();
  state$.next({ value: prev.value - 1, updatedAt: Date.now() });
}
```

Use a `ReplaySubject<T>(3)`. Unlike `BehaviorSubject` (1 latest value, requires an initial) a `ReplaySubject` buffers the last N values emitted so far and re-emits them to any new subscriber.

```typescript
import { ReplaySubject, Observable } from "rxjs";

interface DomainEvent {
  type: string;
  at: number;
}

const events$ = new ReplaySubject<DomainEvent>(3);

events$.next({ type: "start", at: 1 });
events$.next({ type: "tick", at: 2 });
events$.next({ type: "tick", at: 3 });
events$.next({ type: "stop", at: 4 });

// Late subscriber: receives the last 3 buffered events (tick@2, tick@3, stop@4).
export const stream$: Observable<DomainEvent> = events$.asObservable();
```

```typescript
import { BehaviorSubject, Observable } from "rxjs";

type AuthState =
  | { kind: "anonymous" }
  | { kind: "authenticated"; userId: string; jwt: string };

const initial: AuthState = { kind: "anonymous" };
const state$ = new BehaviorSubject<AuthState>(initial);

export const auth$: Observable<AuthState> = state$.asObservable();

export function signIn(userId: string, jwt: string): void {
  state$.next({ kind: "authenticated", userId, jwt });
}

export function signOut(): void {
  state$.next({ kind: "anonymous" });
}

// Sync read for middleware that cannot be async.
// getValue() is a code-smell for reactive code — fine for one-shot use.
export function currentAuth(): AuthState {
  return state$.getValue();
}
```

A `Subject` has NO initial value and does not replay anything to late subscribers — fire-and-forget. A `BehaviorSubject` has a seed and hands it to every new subscriber. A command bus wants fire-and-forget (a command dispatched before anyone was listening is simply lost), so `Subject` is the right pick.

```typescript
import { Subject, Observable } from "rxjs";
import { filter } from "rxjs/operators";

type Command =
  | { type: "save"; id: string }
  | { type: "delete"; id: string };

const bus$ = new Subject<Command>();

export const commands$: Observable<Command> = bus$.asObservable();

export function dispatch(cmd: Command): void {
  bus$.next(cmd);
}

export const deletes$: Observable<Command> = commands$.pipe(
  filter((c: Command): c is Extract<Command, { type: "delete" }> => c.type === "delete")
);
```

