```typescript
import { Observable, defer } from "rxjs";
import { shareReplay } from "rxjs/operators";

interface AppConfig {
  apiBase: string;
  featureFlags: readonly string[];
}

declare function httpGetConfig(): Promise<AppConfig>;

// defer wraps the promise so each NEW subscription would re-run it —
// shareReplay({ bufferSize: 1, refCount: true }) makes it run ONCE.
// refCount: true releases the upstream when the last subscriber unsubscribes.
export const config$: Observable<AppConfig> = defer(() => httpGetConfig()).pipe(
  shareReplay({ bufferSize: 1, refCount: true })
);

// Illustration — both subscribers receive the same cached value, one fetch.
declare const consumer: (c: AppConfig) => void;
config$.subscribe(consumer);
config$.subscribe(consumer);
```

Apply `shareReplay({ bufferSize: 1, refCount: true })`. Every new subscriber gets the most recent value immediately and shares the upstream subscription with existing consumers.

```typescript
import { Observable, interval } from "rxjs";
import { shareReplay, take } from "rxjs/operators";

// Cold source: each subscription would restart the interval.
const cold$: Observable<number> = interval(1000).pipe(take(5));

// Hot, replay-1, auto-release when last subscriber leaves.
export const hot$: Observable<number> = cold$.pipe(
  shareReplay({ bufferSize: 1, refCount: true })
);
```

A COLD observable creates a fresh producer per subscription — two subscribers mean two independent HTTP calls, two intervals, two side effects. A HOT observable multicasts a single producer to all subscribers. `shareReplay` sits between them: it subscribes to the cold source exactly once (while at least one downstream subscriber exists) and replays buffered values to newcomers.

```typescript
import { Observable, defer } from "rxjs";
import { shareReplay, tap } from "rxjs/operators";

interface User { id: string; name: string; }

let calls = 0;
declare function getUser(id: string): Promise<User>;

function userCached$(id: string): Observable<User> {
  return defer(() => {
    calls += 1;
    return getUser(id);
  }).pipe(
    tap({ next: (u: User) => console.log("received", u.id) }),
    shareReplay({ bufferSize: 1, refCount: true })
  );
}

const shared$ = userCached$("u1");
shared$.subscribe();
shared$.subscribe();
// calls === 1 — one network hit, both subscribers served.
export { shared$, calls };
```

