```typescript
import { Observable, timer } from "rxjs";
import { retry } from "rxjs/operators";

interface ApiResult<T> {
  status: number;
  body: T;
}

declare function fetchJson$<T>(url: string): Observable<ApiResult<T>>;

export function fetchWithBackoff$<T>(url: string): Observable<ApiResult<T>> {
  // v7+ preferred form. retryWhen is deprecated for this use case.
  return fetchJson$<T>(url).pipe(
    retry({
      count: 3,
      delay: (_err: unknown, retryCount: number): Observable<number> =>
        timer(2 ** retryCount * 100),
    })
  );
}
```

Use `retry({ count, delay })` and throw from the delay callback for errors you do NOT want retried. Returning an observable from `delay` schedules the retry; throwing propagates the error immediately.

```typescript
import { Observable, ObservableInput, timer, throwError } from "rxjs";
import { retry } from "rxjs/operators";

interface ApiError {
  status: number;
  message: string;
}

declare function request$<T>(url: string): Observable<T>;

function isApiError(err: unknown): err is ApiError {
  return typeof err === "object" && err !== null && "status" in err;
}

export function retryNetworkOnly$<T>(url: string): Observable<T> {
  return request$<T>(url).pipe(
    retry({
      count: 2,
      delay: (err: unknown, retryCount: number): ObservableInput<unknown> => {
        if (isApiError(err) && err.status >= 400 && err.status < 500) {
          // 4xx — do not retry, surface the error immediately.
          return throwError(() => err);
        }
        return timer(500 * retryCount);
      },
    })
  );
}
```

`retryWhen` took a notifier observable and was easy to misuse (emitting any value retried, completing stopped retrying). In v7 the `retry({ count, delay })` config form covers the common backoff case with clearer semantics: `delay` returns an observable whose first emission triggers the retry, and you control count separately.

```typescript
import { Observable, timer } from "rxjs";
import { retry } from "rxjs/operators";

declare function loadUser$(id: string): Observable<{ id: string; name: string }>;

export function loadWithBackoff$(id: string): Observable<{ id: string; name: string }> {
  return loadUser$(id).pipe(
    retry({
      count: 4,
      delay: (_err: unknown, n: number): Observable<number> => timer(100 * 2 ** n),
    })
  );
}
```

```typescript
import { Observable, timer } from "rxjs";
import { retry } from "rxjs/operators";

declare function job$<T>(): Observable<T>;

export function jitteredRetry$<T>(): Observable<T> {
  return job$<T>().pipe(
    retry({
      count: 5,
      delay: (_err: unknown, retryCount: number): Observable<number> => {
        const base = 200 * 2 ** (retryCount - 1);
        const jitter = Math.floor(Math.random() * 100);
        return timer(base + jitter);
      },
    })
  );
}
```

