```typescript
import { Observable } from "rxjs";
import { scan } from "rxjs/operators";

interface RunningTotal {
  count: number;
  sum: number;
  mean: number;
}

declare const value$: Observable<number>;

const seed: RunningTotal = { count: 0, sum: 0, mean: 0 };

// scan emits EVERY intermediate accumulator; reduce would emit once on complete.
export const running$: Observable<RunningTotal> = value$.pipe(
  scan((acc: RunningTotal, v: number): RunningTotal => {
    const count = acc.count + 1;
    const sum = acc.sum + v;
    return { count, sum, mean: sum / count };
  }, seed)
);
