Use `reduce`. It behaves like `Array.prototype.reduce`: it consumes every emission and emits ONE value when the source completes. For intermediate emissions use `scan` instead.

```typescript
import { Observable, from } from "rxjs";
import { reduce } from "rxjs/operators";

const nums$: Observable<number> = from([1, 2, 3, 4]);

export const total$: Observable<number> = nums$.pipe(
  reduce((acc: number, v: number): number => acc + v, 0)
);
```

`scan` takes a seed plus a `(state, action) => state` reducer and emits every new state. Feed it an action stream and you get exactly the Redux model without any library. Downstream consumers simply subscribe to the state observable.

```typescript
import { Observable, Subject } from "rxjs";
import { scan, shareReplay } from "rxjs/operators";

interface State {
  count: number;
}

type Action =
  | { type: "inc" }
  | { type: "dec" }
  | { type: "set"; value: number };

const initial: State = { count: 0 };
const action$ = new Subject<Action>();

function reducer(state: State, action: Action): State {
  switch (action.type) {
    case "inc": return { count: state.count + 1 };
    case "dec": return { count: state.count - 1 };
    case "set": return { count: action.value };
  }
}

export const state$: Observable<State> = action$.pipe(
  scan<Action, State>(reducer, initial),
  shareReplay({ bufferSize: 1, refCount: true })
);

export function dispatch(a: Action): void {
  action$.next(a);
}
```

