```typescript
import { OperatorFunction, pipe } from "rxjs";
import { map, tap } from "rxjs/operators";

export function logAndMap<T, R>(
  fn: (t: T) => R,
  tag: string
): OperatorFunction<T, R> {
  // Standalone pipe() from "rxjs" — NOT the method .pipe on an observable.
  return pipe(
    tap((t: T) => console.log(tag, t)),
    map(fn)
  );
}

import { Observable, of } from "rxjs";

export const example$: Observable<number> = of(1, 2, 3).pipe(
  logAndMap((n: number): number => n * 2, "doubling")
);
```

