declare function load$(id: string): Observable<string>;
export const out$ = id$.pipe(switchMap((id) => load$(id)));
```

Here is the extended pipeline. `tap` returns the same observable — it is for observation, not transformation. The v7-preferred observer form makes it easy to log errors and completion too.

```typescript
import { Observable } from "rxjs";
import { switchMap, tap } from "rxjs/operators";

declare const id$: Observable<string>;
declare function load$(id: string): Observable<string>;

export const out$: Observable<string> = id$.pipe(
  switchMap((id: string) => load$(id)),
  tap({
    next: (v: string): void => console.log("loaded", v),
    error: (e: unknown): void => console.error("load failed", e),
    complete: (): void => console.log("stream complete"),
  })
);
```
